export function waitForAuth(timeout=5000){return new Promise((resolve,reject)=>{if(window.Auth&&window.Auth.Guards){resolve();return;}const startTime=Date.now();const checkInterval=50;const interval=setInterval(()=>{if(window.Auth&&window.Auth.Guards){clearInterval(interval);resolve();}else if(Date.now()-startTime>timeout){clearInterval(interval);reject(new Error('Auth timeout exceeded'));}},checkInterval);});}export function isAdmin(){if(!window.Auth?.Guards)return false;return window.Auth.Guards.isAdmin();}export function isStaff(){if(!window.Auth?.Guards)return false;return window.Auth.Guards.isStaff();}export function isAffiliate(){if(!window.Auth?.Guards)return false;return window.Auth.Guards.isAffiliate();}export async function requireAdmin(redirectUrl='/auth/login.html'){await waitForAuth();if(!isAdmin()){window.location.href=redirectUrl;return false;}return true;}export async function requireStaff(redirectUrl='/auth/login.html'){await waitForAuth();if(!isStaff()){window.location.href=redirectUrl;return false;}return true;}export async function requireAffiliate(redirectUrl='/auth/login.html'){await waitForAuth();if(!isAffiliate()){window.location.href=redirectUrl;return false;}return true;}export async function requireAuth(redirectUrl='/auth/login.html'){await waitForAuth();if(!window.Auth?.Guards?.isLoggedIn()){window.location.href=redirectUrl;return false;}return true;}export function getCurrentUser(){if(!window.Auth?.Guards)return null;return window.Auth.Guards.getCurrentUser();}export function getCurrentUserId(){const user=getCurrentUser();return user?.id||null;}export default{waitForAuth,isAdmin,isStaff,isAffiliate,requireAdmin,requireStaff,requireAffiliate,requireAuth,getCurrentUser,getCurrentUserId};